package apps.showcase.org.apache.struts2.showcase.action;

public class ExampleAction extends ActionSupport { public static final String CONSTANT = "Struts Rocks!" ; public static Date getCurrentDate ( ) { return new Date ( ) ; } public String getName ( ) { return "John Galt" ; } public String [ ] getBands ( ) { return new String [ ] { "Pink Floyd" , "Metallica" , "Guns & Roses" } ; } public List < String > getMovies ( ) { return Arrays . asList ( "Lord of the Rings" , "Matrix" ) ; } public Book getBook ( ) { return new Book ( "Iliad" , "Homer" ) ; } public Map < String , Book > getBooks ( ) { Map < String , Book > books = new HashMap < String , Book > ( ) ; books . put ( "Iliad" , new Book ( "Iliad" , "Homer" ) ) ; books . put ( "The Republic" , new Book ( "The Replublic" , "Plato" ) ) ; books . put ( "Thus Spake Zarathustra" , new Book ( "Thus Spake Zarathustra" , "Friedrich Nietzsche" ) ) ; return books ; } }